-- Aggiorna i post senza hashtag (aggiungi firma in fondo)
UPDATE linkedin_posts 
SET postText = CONCAT(postText, '\n\nAndrea Cinelli | Founder, IDEASMART')
WHERE postText NOT LIKE '%Andrea Cinelli%';

SELECT COUNT(*) as senza_firma_dopo FROM linkedin_posts WHERE postText NOT LIKE '%Andrea Cinelli%';

